import '../lib/merge_policy.dart';
import '../lib/sync_engine.dart';

void ensure(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final phoneEdit = SyncRecord(
    id: 'sealed-note',
    value: 'keep me',
    deleted: false,
    modifiedAt: 700,
    deviceId: 'alpha-phone',
    clock: {'phone': 4},
  );
  final tabletDelete = SyncRecord(
    id: 'sealed-note',
    value: '',
    deleted: true,
    modifiedAt: 700,
    deviceId: 'zulu-tablet',
    clock: {'tablet': 2},
  );
  final engine = SyncEngine([phoneEdit]);
  engine.applyRemote(tabletDelete);
  final converged = engine.records['sealed-note']!;

  ensure(converged.deleted, 'concurrent deletion was resurrected');
  ensure(
    converged.clock['phone'] == 4 && converged.clock['tablet'] == 2,
    'converged record omitted replica history',
  );
}
